sys_script_include.script:
var EQIX_MDM3_Contact_REST = Class.create();
EQIX_MDM3_Contact_REST.prototype = {
    initialize: function() {},

    process: function(request) {
        var payload = null;
        try {

            if (request && request.body && request.body.data) {
                payload = request.body.data;

            } else if (request && request.body) {
                try {
                    payload = (typeof request.body === 'string') ? JSON.parse(request.body) : request.body;
                } catch (e) {
                    gs.error('REST Import Contact:Invalid JSON in request.body.data - ' + e.message);
                    throw e;
                }
            }

            // Support either { data: [...] } or just [...]
            var arr = [];
            if (payload && Array.isArray(payload.data)) {
                arr = payload.data;
            } else if (Array.isArray(payload)) {
                arr = payload;

            } else if (payload && payload.data && typeof payload.data === 'object') {
                // In case data is a single object instead of array
                arr = [payload.data];
            }

            if (!arr || arr.length === 0) {
                throw new Error('REST Import Contacts: No data records found in payload (expected data[0]).');
            }

            // var obj = arr[0];
            var sysIds = [];
            arr.forEach(function(obj) {
                    // Create GlideRecord for u_imp_legal_account_mdm3
                    var grImpContact = new GlideRecord('u_imp_contact_mdm3_0');
                    grImpContact.initialize();

                    // Root / account-level
                    grImpContact.u_accountname = obj.accountName || '';
                    grImpContact.u_accountnumber = obj.accountNumber || '';
                    grImpContact.u_mdmid = obj.mdmId || '';
                    grImpContact.u_createdby = obj.createdBy || '';
                    grImpContact.u_createddatetime = obj.createdDateTime || '';
                    grImpContact.u_updatedby = obj.updatedBy || '';


                    // Name / person info
                    grImpContact.u_firstname = obj.firstName || '';
                    grImpContact.u_middlename = obj.middleName || '';
                    grImpContact.u_lastname = obj.lastName || '';
                    grImpContact.u_name = obj.name || '';
                    grImpContact.u_nameprefix = obj.namePrefix || '';
                    grImpContact.u_namesuffix = obj.nameSuffix || '';
                    grImpContact.u_salutation = obj.salutation || '';
                    grImpContact.u_pronouns = obj.pronouns || '';
                    grImpContact.u_gender = obj.gender || '';
                    grImpContact.u_dateofbirth = obj.dateOfBirth || '';
                    grImpContact.u_title = obj.title || '';
                    grImpContact.u_designation = obj.designation || '';
                    grImpContact.u_jobtitlegroup = obj.jobTitleGroup || '';
                    grImpContact.u_senioritylevel = obj.seniorityLevel || '';

                    // Status / lifecycle
                    grImpContact.u_status = obj.status || '';
                    grImpContact.u_statuschangedatetime = obj.statusChangeDateTime || '';
                    grImpContact.u_isdeleted = obj.isDeleted;
                    grImpContact.u_isprimary = obj.isPrimary || '';
                    grImpContact.u_leadsource = obj.leadSource || '';
                    grImpContact.u_purgestatus = obj.purgeStatus || '';

                    // Region
                    grImpContact.u_region = obj.region || '';

                    // Comments, communication, employment
                    grImpContact.u_commenters = obj.commenters || '';
                    grImpContact.u_communication = obj.communication || '';
                    grImpContact.u_employmenthistory = obj.employmentHistory || '';

                    // Preferred communication
                    grImpContact.u_preferredmodeofcommunication = obj.preferredModeOfCommunication || '';

                    // --- Email block ---
                    if (obj.email) {
                        grImpContact.u_email_email = obj.email[0].email || '';
                        grImpContact.u_email_emailtype = obj.email[0].emailType || '';
                    }
                    // --- Phone block ---
                    if (obj.phone) {
                        var mobile = obj.phone.find(item => item.type.toLowerCase().includes('mobile'));
                        var business = obj.phone.find(item => item.type.toLowerCase().includes('business'));
                        grImpContact.u_phone_number = business.number || '';
                        grImpContact.u_mobile_number = mobile.number || '';
                        grImpContact.u_phone_extension = business.extension || '';
                        // grImpContact.u_phone_type = obj.phone[0].type || '';
                        // grImpContact.u_phone_number = obj.phone[0].number || '';
                    }

                    /*// --- Privacy preferences ---
                    grImpContact.u_privacyprefe_e_donotcontact = (obj.privacyPreference?.doNotContact ?? '').toString();
                    grImpContact.u_privacyprefe_ce_emailoptout = (obj.privacyPreference?.emailOptOut ?? '').toString();
                    grImpContact.u_privacypreference_faxoptout = (obj.privacyPreference?.faxOptOut ?? '').toString();*/

                    // --- Associated accounts array ---
                    // Store raw JSON as string (matching your example where value is a JSON array in a single field)
                    grImpContact.u_associatedaccounts_arraydata = JSON.stringify(obj.associatedAccounts);



                    // Insert the record
                    sysIds.push(grImpContact.insert());
                    // gs.info('Record created in u_imp_legal_account_mdm3 with sys_id: ' + sysId);
                }

            );


            return "ImpMDM3contact created: " + sysIds.join(',');

        } catch (e) {
            /*var msLog = new EQIX_ManagedServiceLog();
            msLog.errorLog('u_imp_legal_account_mdm3', case_id, 'Script REST', '/api/equi2/eqix_novation/createCase', e.message, 'create');*/
            gs.error('REST Import Contact: Not possible to create Record  in u_imp_legal_contact_mdm3 with : ' + e.stack);
            var mslog = new EQIX_ManagedServiceLog();
            mslog.errorLog('customer_contact', '', 'Scripted REST API', 'EQIX_MDM3_Account_and_Contact.ImportMDM3Contact', (request.getHeader('CORRELATION-ID') || '') + '. Error: ' + e.message, '/api/equi2/eqix_mdm3/importContact');
            // gs.eventQueue('EQIX.accounts.contacts.error', null, 'REST Import Contact \n' + request.path + '. ' + request.getHeader('CORRELATION-ID') + 'Error: ' + e.message);

        }
    },

    type: 'EQIX_MDM3_Contact_REST'
};
